import { useState } from "react";
export const useHTTP = (url) => {
  const [load = false, setLoading] = useState;
  async function http(params) {
    try {
      setLoading(false);
      const response = await fetch(url, { method: "GET" });
      const json = await response.json();
      setLoading(true);
      return json;
    } catch (error) {
      console.log(error);
    }
  }
  http().then((e) => add(e));
  function add(e) {
    e.forEach((element) => {
      arr.push(element);
    });
  }
  let arr = [];
  console.log(arr);
};
